import React, { useState, useRef, useEffect } from "react";
import "../styles/CrisisSupport.css"; // keep your existing styles

const HIGH_RISK = [
  "commit suicide",
  "kill myself",
  "want to die",
  "end my life",
  "suicidal",
  "i dont want to live"
];

const HELP_SEEKING = [
  "remove these thoughts",
  "stop these thoughts",
  "what should i do",
  "help me",
  "i feel hopeless",
  "negative thoughts"
];

export default function CrisisSupport() {
  const [messages, setMessages] = useState([
    {
      sender: "ai",
      text: "Hi, I’m here with you. You don’t have to go through this alone. Tell me what’s been troubling you."
    }
  ]);
  const [input, setInput] = useState("");
  const chatEndRef = useRef(null);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  const analyzeMessage = (text) => {
    const lower = text.toLowerCase();

    if (HIGH_RISK.some(word => lower.includes(word))) {
      triggerEmergencyAlert();

      return `
I’m really sorry that you’re feeling this much pain right now.
What you’re going through is very heavy — but your life truly matters.

These thoughts can feel overwhelming, but they *can* pass.
You are not weak for feeling this way.

If possible, please reach out to someone you trust right now.
You deserve care, understanding, and support.

Let’s pause together for one slow breath:
Inhale… hold… exhale slowly.

I’m here with you.
`;
    }

    if (HELP_SEEKING.some(word => lower.includes(word))) {
      return `
I’m really glad you asked for help — that takes strength.

Here are a few gentle things that may help reduce these thoughts:
• Take 5 slow, deep breaths
• Sit somewhere safe and grounded
• Put your feet on the floor and name 3 things you see

Some people find comfort in hopeful movies:
🎬 The Pursuit of Happyness  
🎬 Inside Out  
🎬 A Beautiful Mind  
🎬 Soul  

You don’t have to solve everything today.
Small steps are enough.
`;
    }

    return "I’m listening. Please tell me more about what you’re feeling.";
  };

  const triggerEmergencyAlert = () => {
    console.warn("🚨 Emergency alert triggered (backend integration needed)");
    // Later: API call to backend (Twilio SMS)
  };

  const sendMessage = () => {
    if (!input.trim()) return;

    const userMsg = { sender: "user", text: input };
    const aiReply = {
      sender: "ai",
      text: analyzeMessage(input)
    };

    setMessages(prev => [...prev, userMsg, aiReply]);
    setInput("");
  };

  return (
    <div className="chat-container">
      <div className="chat-header">Crisis Support</div>

      <div className="chat-body">
        {messages.map((msg, i) => (
          <div
            key={i}
            className={msg.sender === "user" ? "user-msg" : "ai-msg"}
          >
            {msg.text}
          </div>
        ))}
        <div ref={chatEndRef} />
      </div>

      <div className="chat-footer">
        <input
          type="text"
          placeholder="Type how you're feeling..."
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={(e) => e.key === "Enter" && sendMessage()}
        />
        <button onClick={sendMessage}>Send</button>
      </div>

      {/* Emergency Help Section */}
      <div className="emergency-box">
        <p><strong>If you are in immediate danger:</strong></p>
        <p>📞 India Suicide Helpline: <strong>9152987821</strong></p>
        <p>🌍 International: <strong>findahelpline.com</strong></p>
      </div>
    </div>
  );
}
